import json
import requests

def lambda_handler(event, context):
    # Get the request from the event
    request = event['Records'][0]['cf']['request']
    headers = request['headers']
    
    # Extract the X-Enrich-URL header
    enrich_url = headers.get('x-enrich-url', [{}])[0].get('value', None)

    if enrich_url:
        try:
            # Fetch additional data from the specified URL
            response = requests.get(enrich_url)
            response_data = response.json()
        except Exception as e:
            # Handle any errors that occur during the HTTP request
            return {
                'statusCode': 500,
                'statusDescription': 'Internal Server Error',
                'body': json.dumps({'error': str(e)})
            }
        
        # Modify the request or add context data as needed
        request['headers']['x-enriched-data'] = [{'key': 'x-enriched-data', 'value': json.dumps(response_data)}]
    
    # Return the modified request to continue to the origin
    return request